// Ferocious Kitten - MarkiRAT Telegram hijack + fake Google updater persistence
let susp_paths = dynamic([@"\AppData\Roaming\Telegram Desktop\", @"\AppData\Local\Google\Update\", @"\AppData\Roaming\Microsoft\Windows\Start Menu\Programs\Startup\"]);
let susp_names = dynamic(["GoogleUpdate.exe","Update.exe","chrome_updater.exe","svchost.exe","Telegram.exe"]);
let drops =
DeviceFileEvents
| where Timestamp > ago(30d)
| where ActionType in ("FileCreated","FileRenamed","FileModified")
| where FolderPath has_any (susp_paths)
| where FileName in~ (susp_names)
| where InitiatingProcessFileName !in~ ("Telegram.exe","TelegramSetup.exe","GoogleUpdate.exe","msiexec.exe")
| project DropTime=Timestamp, DeviceId, DeviceName, FileName, FolderPath, SHA256, InitiatingProcessFileName, InitiatingProcessCommandLine;
let execs =
DeviceProcessEvents
| where Timestamp > ago(30d)
| where FileName in~ (susp_names)
| where FolderPath has_any (susp_paths)
| where InitiatingProcessFileName in~ ("explorer.exe","Telegram.exe","cmd.exe","wscript.exe","rundll32.exe")
| project ExecTime=Timestamp, DeviceId, FileName, FolderPath, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine, AccountName, SHA256;
drops
| join kind=inner (execs) on DeviceId, SHA256
| where ExecTime between (DropTime .. (DropTime + 7d))
| project DropTime, ExecTime, DeviceName, FileName, FolderPath, SHA256, DropParent=InitiatingProcessFileName, ExecParent=InitiatingProcessFileName1, ProcessCommandLine, AccountName
| order by DropTime desc
